(()=>{function e(e){fetch(e).then(e=>e.text()).then(e=>{let s=new DOMParser,n=s.parseFromString(e,"text/html");document.getElementById("main-content").innerHTML=n.getElementById("main-content").innerHTML,console.log(n.getElementsByTagName("title")[0].innerHTML),document.getElementsByTagName("title")[0].innerHTML=n.getElementsByTagName("title")[0].innerHTML;let o=document.getElementsByClassName("nav");for(button of o)button.addEventListener("click",t);window.scrollTo(0,0)}).catch(e=>console.warn(e))}function t(t){t.preventDefault();let n=t.target.getAttribute("href");if(n){e(n),history.pushState({},"",n);let t=document.getElementById("left-sidebar");t.className!=="sidebar"&&(t.style.width="0px",t.className="sidebar")}else console.error("nav link has no path")}})()